INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-57f41407-moex-00603', 'judicial-57f41407', 'judicial-57f41407-moex-111-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「地圖是對世界提出一份建議書，而非單純地反映世界，同時每一份建議書都出自某個文化主流的假設和 既有見解。地圖和這些假設及見解之間的關係總是有來有往，但未必是固定或穩定的。……每幅地圖不 但說明了世界，也屬於這個世界。對歷史學家而言，這些地圖都創造出適合的條件，讓我們瞭解一個主流 理念——宗教、政治、平等、寬容——我們透過這個理念來理解自己，同時瞭解我們周圍的世界。」 根據上文，下列選項何者最符合文意？', '["通過地圖，我們可以理解歷史學家的主流理念", "地圖往往為權力者所利用，展現各種政治霸權", "地圖真實反映世界，所以能幫助人們創造適合的居住條件", "地圖幫助我們瞭解周圍的世界，使我們對主流理念更清晰"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "9590982026e4", "answer_pdf_sha1": "a7948f89865b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00604', 'judicial-57f41407', 'judicial-57f41407-moex-111-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「自1624至1661年荷蘭東印度公司所招募來臺的二萬多閩南移民，並未有祭拜太子爺的記載。這一 點很值得注意。臺灣最早的太子廟，是新營太子宮，建於康熙二年（1663年），正是鄭成功驅離荷人 的翌年。鄭氏部將何替仔到此屯田，旗號叫『新營』，『結廬奉祀中壇元帥』。也就是一安頓下來，就 建茅屋拜起三太子，直到現在，連地名都叫『太子宮』。」 根據上文，下列選項何者正確？', '["何替仔奉鄭成功之令，在「新營」興建廟宇供奉中壇元帥，形成太子爺信仰", "荷蘭東印度公司招募來臺二萬多的閩南移民，於是引入閩南人的太子爺信仰", "臺灣太子爺信仰發端於「新營」，1663年由何替仔在此屯田並立廟奉祀", "鄭成功驅除荷蘭人，為安撫臺灣大量閩南移民，所以創立太子宮以安定民心"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "9590982026e4", "answer_pdf_sha1": "a7948f89865b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00605', 'judicial-57f41407', 'judicial-57f41407-moex-111-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「一名大學生勤奮練習雙手拋接球，練到能同時拋接三顆球而且一分鐘不讓球落地，這時掃描一次大 腦；休息三個月後，再進入實驗室掃描大腦。大腦造影研究發現，大腦頂葉掌管空間運動的地方在大 量練習時活化區域比較大，三個月不練後縮小了。」 根據上文，下列選項最不相關的是？', '["人只要活著就能改變自己，活到老，可以學到老", "大腦的連結因為需求而改變，其特性是用進廢退", "後天環境的行為表現，也會影響大腦的運作機制", "不要輕易放棄，從什麼地方跌倒就從那裡站起來"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "9590982026e4", "answer_pdf_sha1": "a7948f89865b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00606', 'judicial-57f41407', 'judicial-57f41407-moex-111-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「偏好尖頭木筷還有一點，唇舌的碰觸面積小，木頭質地的異體感最輕微，口腔全體正在享受食物的 口感和香氣那當下，忽然介入樹脂的碰觸太干擾，更別提不鏽鋼，辜負白米，辜負農夫，辜負太陽和 地球，辜負自他辛勤耕耘才有的這一刻，想吃卻又閒定。」 根據上文，下列選項最貼近作者旨趣的是：', '["尖頭木筷對味覺影響最小，較能保留米飯應有的口感及香氣", "樹脂筷常含有過量化合物，會對米飯入口時的香氣造成干擾", "享用食物時不宜狼吞虎嚥，唯有優雅入口才能感受農夫心意", "合宜餐具可突出米飯特徵，同時反映其栽培環境與種植技術"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "9590982026e4", "answer_pdf_sha1": "a7948f89865b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00607', 'judicial-57f41407', 'judicial-57f41407-moex-111-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「我寫的《科學革命的結構》一書，出版至今已好幾年了。這本書能被廣泛閱讀，引發形形色色的討 論和批評，我深感欣慰。但有一種情況讓我覺得沮喪，那就是不少評論者雖各有所見，卻很難相信他 們在探討同一本書。我更不得不遺憾地說，這本書之所以成功，其中一個原因竟是：它幾乎滿足所有 人的論述需求。」 根據上文，何者最符合作者對《科學革命的結構》一書的想法？', '["事實證明這本書是失敗之作", "遺憾這本書未獲得廣大迴響", "不滿這本書的版權屢遭剽竊", "不少人誤解了這本書的內容"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "9590982026e4", "answer_pdf_sha1": "a7948f89865b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00608', 'judicial-57f41407', 'judicial-57f41407-moex-111-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「人類天生具有語言天賦，但要學會說話，必須先聽到別人說話。如果孩童在學習的關鍵時期缺乏其 他人提供的語言刺激，他們將無法學會說話，即使他們天生具備這項潛能。在一般情況下，每個人先 天都有識字的潛能，但這世上卻有許多人不識字。讀書寫字的能力並不是隨著年紀增長就能擁有的， 它和說話一樣，是文化培育造就出來的。」 根據上文，下列選項何者最符合文意？', '["認識天賦有助於潛能開發", "無法從現有能力找出潛能", "具備天賦不等於擁有能力", "天賦影響後天能力的培養"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "9590982026e4", "answer_pdf_sha1": "a7948f89865b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00609', 'judicial-57f41407', 'judicial-57f41407-moex-111-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「臺灣社會歷經移民、殖民，這種悲情中摻雜樂觀奮鬥的文化，表現在我們早期的代工業，或者後來 的高科技產業。近年來電影工業的復興也反應了這種特殊的文化。國片曾經有過一年只有八部，總票 房不滿一千萬的慘況，但是電影工作者卻帶著宗教般的理想與信仰，前仆後繼地投入，終於產業奇蹟 似地復興了。像2008年《海角七號》、2010年《艋舺》都有超過上億的票房。」 根據上文，作者認為臺灣電影工業復興最重要的因素是什麼？', '["移民殖民的歷史", "產業的景氣循環", "人們的努力信念", "上億票房的保證"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "9590982026e4", "answer_pdf_sha1": "a7948f89865b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00610', 'judicial-57f41407', 'judicial-57f41407-moex-111-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「某歐洲交換學生於簽證期滿後，想繼續留臺學習華語，卻被外交部拒絕，引起外界質疑」，外交部發 文澄清，說明如下： 「如果本國學校及歐洲學生的母校雙方皆同意學生延長交換期限，行文外交部領事事務局並附相關 證明，外交部可協助辦理簽證。如果是以臺歐連結獎學金來臺灣研習華語，期滿擬繼續留在臺灣 研習華語者，只要有就讀學校出具三個月註冊證明，外交部可據以協助辦理簽證。如果臺歐連結 獎學金學生交換期滿，擬續於臺灣改為就讀正式學位，外交部將專案協助申辦簽證。」 根據上文，下列選項正確的是﹕', '["延長交換期限，必須經臺歐雙方學校同意", "研習華語期滿必須先返國，重新申請來臺", "臺歐連結獎學金學生可逕行攻讀正式學位", "專案簽證流程約3個月，校方須協助註冊"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "9590982026e4", "answer_pdf_sha1": "a7948f89865b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00611', 'judicial-57f41407', 'judicial-57f41407-moex-111-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「如同藝術品，茶也需要一雙大師的巧手，才能泡製出最高貴的質地。茶有好壞之分，正如畫有高下 之別——雖說我們擁有的，大多是後者。要完成一碗絕頂好茶，手法並不固定，每一種茶葉的調理方 法都是獨一無二的，包括與不同水量水溫的契合程度、各自繼承到的前人智慧，以及調理者個人的敘 事風格。」 根據上文，下列選項最符合作者觀點的是：', '["茶葉調理者，都可塑造個人專屬的敘事風格", "泡茶必須依循前人，以形成自己固定的手法", "泡製質地高貴的好茶，茶葉的好壞重於手藝", "茶葉調理的第一個步驟，必須考量水量水溫"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "9590982026e4", "answer_pdf_sha1": "a7948f89865b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00612', 'judicial-57f41407', 'judicial-57f41407-moex-111-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「走進機艙，我以為自己很勇敢，一找到座位，心從很深的內核酸楚了起來。那時媽媽過世，我辭掉 好不容易才輾轉進入的報社，那一年，初次懂得愛情裡複雜殘酷的況味。我告別的不是愛情，不是記 者工作，而是純真的少女年華，我告別我自己。當飛機起飛的時候，我似乎無意識地，在心頭響起這 支歌：『風好像倦了，雲好像累了，這世界再沒有，屬於自己的夢想。我走過青春，我失落年少……』 是誰寫的歌詞，在那時刻，完完全全熨貼著我的心？」 根據上文，歌詞能觸動作者的原因是：', '["其所搭配的歌曲旋律非常悅耳動聽", "歌詞產生的酸楚感受呼應窗外景物", "適當對應著作者當時的遭遇與心境", "將純真的少女情懷轉作成長的記憶"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "9590982026e4", "answer_pdf_sha1": "a7948f89865b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
